sql:
SELECT hitid
FROM hit_status
WHERE hitstatus = 'Completed' AND reviewstatus = 'Reviewed';

SELECT COUNT(DISTINCT workerid) 
FROM assignments 
WHERE assignmentstatus = 'Approved';

SELECT DISTINCT e.hitid
FROM experiments e
WHERE e.category LIKE '%image labeling%' AND e.description IS NOT NULL;

SELECT workerid, average_response_time 
FROM worker_performance 
WHERE total_assignments_completed > 50;

SELECT COUNT(DISTINCT a.workerid) AS total_workers
FROM assignments a
JOIN responses r ON a.assignmentid = r.assignmentid;

SELECT DISTINCT workerid
FROM feedback
WHERE is_helpful = 0;

external_knowledge:
- "shining stars" refers to workers with high performance;
- "brightest accuracy constellations" metaphorically describes the highest average accuracy;
- "sky of productivity" symbolizes the performance metrics;
- "how long does it take for them to respond on average" refers to the average response time.

sql:
SELECT average_accuracy, average_response_time, total_earnings
FROM worker_performance
WHERE workerid = 1;

external_knowledge:
- "just emerged from adolescence" refers to ages between 20 and 30;
- "not yet at the peak of their career" implies occupations such as Student, Employed, or Unemployed;
- "planted over fifty seeds in the fertile ground of assignments" means completing more than 50 assignments;
- "using either the Windows or MacOS tools" refers to the operating systems used by the workers;
- "one who has harvested the greatest bounty" points to the highest earnings;
- "identities" refer to worker ID and other personal information;
- "ecosystems in which they thrive" is related to their native language;
- "richness of their harvest" is the total earnings of the worker.
